class Solution:
    def containsNearbyDuplicate(self, nums: list[int], k: int) -> bool:
        num_map = {}  # Stores num -> last_seen_index

        for i, num in enumerate(nums):
            if num in num_map:
                if abs(i - num_map[num]) <= k:
                    return True
            num_map[num] = i  # Update with the current index

        return False
